71	export async function navigateTo(page: Page, path: string) {
72	  try {
73	    await page.evaluate((p) => {
74	      const router = (window as any).ng?.getComponent(document.querySelector('app-root'))?.router;
75	      if (router) {
76	        router.navigateByUrl(p);
77	        return;
78	      }
79	      // Fallback: use Angular's injector
80	      const appRef = (window as any).ng?.coreTokens?.ApplicationRef;
