    // If hostname is a literal IP, check CIDR blocklist directly
    if (isIpAddress(hostname)) {
      return !isBlockedIp(hostname);
    }

    // DNS resolution check — prevent rebinding to metadata IPs
    try {
      const results = await Promise.allSettled([
        resolve4(hostname),
        resolve6(hostname),
