1	/**
2	 * Test harness for Fastify route integration tests (mock-DB tier).
3	 *
4	 * Builds a real Fastify app with actual route handlers, a mock DB layer,
5	 * and an auth decorator that mirrors real behavior:
6	 *   - JWT signature + expiration verification (real @fastify/jwt)
7	 *   - Session nonce validation against mock user_sessions table
8	 *   - Org-isolation context setting (SET LOCAL calls on mock db.raw)
9	 *
10	 * WHAT THIS COVERS: route handler logic, authorization guards, input
11	 * validation, response sanitization, ownership checks, role transitions.
12	 *
13	 * WHAT THIS CANNOT COVER (requires real PostgreSQL):
14	 *   - Row-Level Security (RLS) policy enforcement at the database layer
15	 *   - Advisory lock contention under concurrent writes
16	 *   - Real transaction isolation and rollback behavior
17	 *
18	 * For those behaviors, see: src/api/routes/real-db-integration.test.ts
19	 * which runs against a live PostgreSQL instance when DATABASE_URL is set.
20	 */
21	import Fastify, { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify';
22	import jwt from '@fastify/jwt';
23	import { Knex } from 'knex';
24	
25	const JWT_SECRET = 'test-jwt-secret-at-least-32-characters!!';
26	
27	/**
28	 * Creates a chainable mock that mimics Knex query builder behaviour.
29	 */
30	function createQueryChain(rows: any[]) {
31	  let filtered = [...rows];
32	
33	  const chain: any = {
34	    where(arg: any, op?: any, val?: any) {
35	      if (typeof arg === 'function') {
36	        // where(function() { this.where(...).orWhere(...) }) — callback style
37	        arg.call(chain);
38	      } else if (typeof arg === 'object') {
39	        filtered = filtered.filter(r =>
40	          Object.entries(arg).every(([k, v]) => r[k] === v)
41	        );
42	      } else if (typeof arg === 'string' && val !== undefined) {
43	        // 3-arg: where(col, op, val)
44	        filtered = filtered.filter(r => {
45	          const rv = r[arg];
46	          if (op === '>') return rv > val;
47	          if (op === '>=') return rv >= val;
48	          if (op === '<') return rv < val;
49	          if (op === '<=') return rv <= val;
50	          if (op === '=') return rv === val;
51	          return rv === val;
52	        });
53	      } else if (typeof arg === 'string' && op !== undefined && val === undefined) {
54	        // 2-arg: where(col, val)
55	        filtered = filtered.filter(r => r[arg] === op);
56	      }
57	      return chain;
58	    },
59	    whereIn(col: string, values: any) {
60	      // values can be an array or a thenable (subquery chain)
61	      if (Array.isArray(values)) {
62	        filtered = filtered.filter(r => values.includes(r[col]));
63	      }
64	      // Subquery chains are not easily resolvable synchronously in mock;
65	      // skip filtering for subquery (rely on route-level tests, not DB behavior)
66	      return chain;
67	    },
68	    whereNull(col: string) {
69	      filtered = filtered.filter(r => r[col] == null);
70	      return chain;
71	    },
72	    orWhere(arg: any) {
73	      // Union: add rows from original set that match the orWhere condition
74	      if (typeof arg === 'object') {
75	        const additional = rows.filter(r =>
76	          Object.entries(arg).every(([k, v]) => r[k] === v)
77	        );
78	        for (const row of additional) {
79	          if (!filtered.includes(row)) filtered.push(row);
80	        }
81	      }
82	      return chain;
83	    },
84	    whereNot(arg: any) {
85	      if (typeof arg === 'object') {
86	        filtered = filtered.filter(r =>
87	          !Object.entries(arg).every(([k, v]) => r[k] === v)
88	        );
89	      }
90	      return chain;
91	    },
92	    first() {
93	      return Promise.resolve(filtered[0] ?? null);
94	    },
95	    count(_col?: string) {
96	      return { first: () => Promise.resolve({ count: filtered.length }) };
97	    },
98	    orderBy() { return chain; },
99	    limit() { return chain; },
100	    offset() { return chain; },
101	    select() { return chain; },
102	    distinct() { return chain; },
103	    join() { return chain; },
104	    clone() { return createQueryChain([...filtered]); },
105	    insert(data: any) {
106	      const row = Array.isArray(data) ? data[0] : data;
107	      const newRow = { id: 'mock-id-' + Date.now(), ...row, created_at: new Date() };
108	      rows.push(newRow);
109	      return { returning: () => Promise.resolve([newRow]) };
110	    },
111	    update(data: any) {
112	      for (const row of filtered) {
113	        Object.assign(row, data);
114	      }
115	      return { returning: () => Promise.resolve(filtered) };
116	    },
117	    del() { return Promise.resolve(filtered.length); },
118	    increment() { return { returning: () => Promise.resolve(filtered) }; },
119	    then(resolve: any) { return Promise.resolve(filtered).then(resolve); },
120	  };
121	
122	  return chain;
123	}
124	
125	export interface MockDbData {
126	  [tableName: string]: any[];
127	}
128	
129	/**
130	 * Creates a mock Knex-like transaction object backed by in-memory data.
131	 */
132	export function createMockDb(data: MockDbData = {}): Knex.Transaction {
133	  const db: any = (tableName: string) => {
134	    if (!data[tableName]) data[tableName] = [];
135	    return createQueryChain(data[tableName]);
136	  };
137	  db.raw = async (_sql: string, _params?: any[]) => ({ rows: [] });
138	  db.transaction = async (fn: (trx: any) => Promise<any>) => fn(db);
139	  return db as Knex.Transaction;
140	}
141	
142	export interface TestUser {
143	  userId: string;
144	  orgId: string;
145	  role: string;
146	  nonce?: string;
147	}
148	
149	/**
150	 * Builds a Fastify app with real route handlers and a mock DB layer.
151	 *
152	 * The auth decorator mirrors real production behavior:
153	 *   1. Verifies JWT signature and expiration
154	 *   2. Validates session nonce against mock user_sessions table
155	 *   3. Sets org-isolation RLS context variables (via mock db.raw)
156	 *
157	 * This means tests must seed user_sessions for authenticated requests
158	 * to succeed, or use the convenience `signTestToken` helper which
159	 * auto-seeds a matching session.
160	 */
161	export async function buildTestApp(options: {
162	  mockData?: MockDbData;
163	  routes: Array<(app: FastifyInstance) => Promise<void>>;
164	}): Promise<FastifyInstance> {
165	  const app = Fastify({ logger: false });
166	  const mockData = options.mockData ?? {};
167	
168	  // Ensure session table exists in mock data
169	  if (!mockData['user_sessions']) mockData['user_sessions'] = [];
170	
171	  await app.register(jwt, { secret: JWT_SECRET, sign: { expiresIn: '1h' } });
172	
173	  // Auth decorator: mirrors real jwt-auth.plugin.ts behavior
174	  app.decorate('authenticate', async (request: FastifyRequest, reply: FastifyReply) => {
175	    try {
176	      await request.jwtVerify();
177	    } catch {
178	      reply.status(401).send({ error: 'UNAUTHORIZED', message: 'Invalid or expired token' });
179	      return;
180	    }
181	
182	    // Validate session nonce against mock DB (same as real plugin)
183	    const { userId, orgId, role, nonce } = request.user;
184	    const session = await request.db('user_sessions')
185	      .where({ user_id: userId, session_nonce: nonce })
186	      .first();
187	
188	    if (!session) {
189	      reply.status(401).send({
190	        error: 'UNAUTHORIZED',
191	        message: 'Session expired or revoked. Please log in again.',
192	      });
193	      return;
194	    }
195	
196	    // Set org-isolation context (mirrors real jwt-auth.plugin.ts:60-67)
197	    if (role === 'super_admin') {
198	      await request.db.raw("SET LOCAL app.current_org_id = ''");
199	    } else {
200	      await request.db.raw('SET LOCAL app.current_org_id = ?', [orgId]);
201	    }
202	    await request.db.raw('SET LOCAL app.current_role = ?', [role]);
203	    await request.db.raw('SET LOCAL app.current_user_id = ?', [userId]);
204	    await request.db.raw("SET LOCAL app.bypass_rls = 'false'");
205	  });
206	
207	  // Mock org-isolation: set request.db to mock transaction
208	  app.addHook('onRequest', async (request: any) => {
209	    request.db = createMockDb(mockData);
210	  });
211	
212	  // Register real routes
213	  for (const route of options.routes) {
214	    await app.register(route);
215	  }
216	
217	  await app.ready();
218	  return app;
219	}
220	
221	/**
222	 * Sign a JWT for test use and auto-seed a matching session in mock data.
223	 */
224	export function signTestToken(app: FastifyInstance, mockData: MockDbData, user: TestUser): string {
225	  const nonce = user.nonce ?? `nonce-${user.userId}`;
226	  const token = app.jwt.sign({
227	    userId: user.userId,
228	    orgId: user.orgId,
229	    role: user.role,
230	    nonce,
231	    jti: `jti-${user.userId}`,
232	  });
233	
234	  // Auto-seed a matching session so nonce validation passes
235	  if (mockData && mockData['user_sessions']) {
236	    // Avoid duplicates
237	    const exists = mockData['user_sessions'].some(
238	      (s: any) => s.user_id === user.userId && s.session_nonce === nonce
239	    );
240	    if (!exists) {
241	      mockData['user_sessions'].push({
242	        id: `session-${user.userId}`,
243	        user_id: user.userId,
244	        session_nonce: nonce,
245	        token_jti: `jti-${user.userId}`,
246	        expires_at: new Date(Date.now() + 86400000),
247	        created_at: new Date(),
248	      });
249	    }
250	  }
251	
252	  return token;
253	}
