1	/**
2	 * Real PostgreSQL integration tests.
3	 *
4	 * These tests require a running PostgreSQL instance with migrations applied.
5	 * They validate security-critical behaviors that mock-based tests cannot cover:
6	 *   - Session nonce revocation (second login invalidates first token)
7	 *   - RLS tenant isolation (cross-org reads denied at DB level)
8	 *   - Idempotency TTL enforcement
9	 *   - Advisory lock concurrency protection
10	 *
11	 * Run with: DATABASE_URL=postgresql://... npm run test:integration
12	 *
13	 * IMPORTANT: These tests are MANDATORY. When DATABASE_URL is not set,
14	 * the suite hard-fails to prevent silent acceptance gaps.
15	 */
16	import { describe, it, expect, beforeAll, afterAll } from 'vitest';
17	
18	const DATABASE_URL = process.env.DATABASE_URL;
19	const shouldRun = !!DATABASE_URL;
20	
21	describe.skipIf(!shouldRun)('Real PostgreSQL integration tests', () => {
22	  let app: any;
23	  let db: any;
24	
25	  beforeAll(async () => {
26	    const { initDatabase } = await import('../../infrastructure/database/connection.js');
27	    const { buildServer } = await import('../server.js');
28	
29	    db = await initDatabase(DATABASE_URL!);
30	    await db.migrate.latest();
31	
32	    // Ensure seed data exists
33	    await db.raw("SET app.bypass_rls = 'true'");
34	    const userCount = await db('users').count('id as count').first();
35	    if (!userCount || Number(userCount.count) === 0) {
36	      await db.seed.run();
37	    }
38	
39	    app = await buildServer();
40	    await app.ready();
41	  });
42	
43	  afterAll(async () => {
44	    if (app) await app.close();
45	    if (db) await db.destroy();
46	  });
47	
48	  it('session revocation: second login invalidates first token', async () => {
49	    // First login
50	    const login1 = await app.inject({
51	      method: 'POST',
52	      url: '/api/auth/login',
53	      payload: { username: 'client2', password: 'SecurePass1!' },
54	    });
55	    expect(login1.statusCode).toBe(200);
56	    const token1 = JSON.parse(login1.payload).token;
57	
58	    // Second login (revokes first session)
59	    const login2 = await app.inject({
60	      method: 'POST',
61	      url: '/api/auth/login',
62	      payload: { username: 'client2', password: 'SecurePass1!' },
63	    });
64	    expect(login2.statusCode).toBe(200);
65	    const token2 = JSON.parse(login2.payload).token;
66	
67	    // First token should now be rejected (nonce revoked)
68	    const meWithOldToken = await app.inject({
69	      method: 'GET',
70	      url: '/api/auth/me',
71	      headers: { authorization: `Bearer ${token1}` },
72	    });
73	    expect(meWithOldToken.statusCode).toBe(401);
74	
75	    // Second token should work
76	    const meWithNewToken = await app.inject({
77	      method: 'GET',
78	      url: '/api/auth/me',
79	      headers: { authorization: `Bearer ${token2}` },
80	    });
81	    expect(meWithNewToken.statusCode).toBe(200);
82	  });
83	
84	  it('RLS tenant isolation: client cannot read cross-org bookings', async () => {
85	    // Login as client1 (org-1)
86	    const loginRes = await app.inject({
87	      method: 'POST',
88	      url: '/api/auth/login',
89	      payload: { username: 'client1', password: 'SecurePass1!' },
90	    });
91	    const token = JSON.parse(loginRes.payload).token;
92	
93	    // List bookings — should only return bookings from client1's org
94	    const bookingsRes = await app.inject({
95	      method: 'GET',
96	      url: '/api/bookings',
97	      headers: { authorization: `Bearer ${token}` },
98	    });
99	    expect(bookingsRes.statusCode).toBe(200);
100	    const body = JSON.parse(bookingsRes.payload);
101	
102	    // All returned bookings should belong to the authenticated user (client scoping)
103	    const me = JSON.parse((await app.inject({
104	      method: 'GET',
105	      url: '/api/auth/me',
106	      headers: { authorization: `Bearer ${token}` },
107	    })).payload);
108	
109	    for (const booking of body.data) {
110	      expect(booking.clientId).toBe(me.user.id);
111	    }
112	  });
113	
114	  it('idempotency: same key+user returns cached response', async () => {
115	    const loginRes = await app.inject({
116	      method: 'POST',
117	      url: '/api/auth/login',
118	      payload: { username: 'client1', password: 'SecurePass1!' },
119	    });
120	    const token = JSON.parse(loginRes.payload).token;
121	
122	    // Get a lawyer ID
123	    const lawyerLogin = await app.inject({
124	      method: 'POST',
125	      url: '/api/auth/login',
126	      payload: { username: 'lawyer1', password: 'SecurePass1!' },
127	    });
128	    const lawyerMe = JSON.parse((await app.inject({
129	      method: 'GET',
130	      url: '/api/auth/me',
131	      headers: { authorization: `Bearer ${JSON.parse(lawyerLogin.payload).token}` },
132	    })).payload);
133	
134	    const idempotencyKey = crypto.randomUUID();
135	    const futureDate = new Date(Date.now() + 200 * 86400000);
136	    futureDate.setHours(9, Math.floor(Math.random() * 60), 0, 0);
137	
138	    // First request
139	    const res1 = await app.inject({
140	      method: 'POST',
141	      url: '/api/bookings',
142	      headers: { authorization: `Bearer ${token}` },
143	      payload: {
144	        lawyerId: lawyerMe.user.id,
145	        type: 'consultation',
146	        scheduledAt: futureDate.toISOString(),
147	        idempotencyKey,
148	      },
149	    });
150	    expect(res1.statusCode).toBe(201);
